import { SxProps, Theme } from '@mui/material/styles';

export function glassPanelSx(): SxProps<Theme> {
  return {
    border: '1px solid rgba(182, 223, 255, 0.26)',
    background: 'linear-gradient(140deg, rgba(14, 35, 58, 0.82), rgba(12, 27, 44, 0.68))',
    backdropFilter: 'blur(16px)',
    WebkitBackdropFilter: 'blur(16px)',
    boxShadow: '0 18px 42px rgba(2, 8, 20, 0.48)',
  };
}
